[
  {
    "function_name": "get_post_detail_with_related_data",
    "definition": "CREATE OR REPLACE FUNCTION public.get_post_detail_with_related_data(p_post_id uuid, p_viewer_user_id uuid DEFAULT NULL::uuid)\n RETURNS jsonb\n LANGUAGE plpgsql\n STABLE SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_viewer_profile_id UUID;\r\n  v_result JSONB;\r\n  v_post JSONB;\r\nBEGIN\r\n  -- Step 1: Get viewer's profile ID if viewer_user_id is provided\r\n  IF p_viewer_user_id IS NOT NULL THEN\r\n    SELECT id INTO v_viewer_profile_id\r\n    FROM profiles\r\n    WHERE user_id = p_viewer_user_id\r\n    LIMIT 1;\r\n  END IF;\r\n\r\n  -- Step 2: Query post with all related data\r\n  SELECT jsonb_build_object(\r\n    'id', p.id,\r\n    'type', p.type,\r\n    'caption', p.caption,\r\n    'created_at', p.created_at,\r\n    'author_id', p.author_id,\r\n    'status', p.status,\r\n    'is_anonymous', p.is_anonymous,\r\n    'anonymous_name', p.anonymous_name,\r\n    'anonymous_avatar', p.anonymous_avatar,\r\n    'visibility', p.visibility,\r\n    'rsvp_capacity', p.rsvp_capacity,\r\n    'selected_dates', p.selected_dates,\r\n    'is_recurring', p.is_recurring,\r\n    'recurrence_days', p.recurrence_days,\r\n    'tags', p.tags,\r\n    -- Author profile\r\n    'author', jsonb_build_object(\r\n      'id', author_profile.id,\r\n      'username', author_profile.username,\r\n      'display_name', author_profile.display_name,\r\n      'avatar_url', author_profile.avatar_url,\r\n      'is_private', author_profile.is_private\r\n    ),\r\n    -- Follow status\r\n    'follow_status', CASE\r\n      WHEN v_viewer_profile_id IS NULL THEN 'none'\r\n      WHEN v_viewer_profile_id = author_profile.id THEN 'self'\r\n      WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n           AND reverse_follow.follower_id IS NOT NULL AND reverse_follow.status = 'approved' \r\n      THEN 'friends'\r\n      WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n      THEN 'following'\r\n      WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'pending' \r\n      THEN 'pending'\r\n      ELSE 'none'\r\n    END,\r\n    -- Like status\r\n    'is_liked', CASE WHEN p_viewer_user_id IS NOT NULL AND user_like.post_id IS NOT NULL THEN true ELSE false END,\r\n    -- Save status\r\n    'is_saved', CASE WHEN p_viewer_user_id IS NOT NULL AND user_save.post_id IS NOT NULL THEN true ELSE false END,\r\n    -- Comment count\r\n    'comment_count', (\r\n      SELECT COUNT(*)\r\n      FROM comments c\r\n      WHERE c.post_id = p.id\r\n        AND c.is_deleted = false\r\n    ),\r\n    -- Has images flag\r\n    'has_images', CASE\r\n      WHEN EXISTS (\r\n        SELECT 1\r\n        FROM activities a\r\n        WHERE a.post_id = p.id\r\n          AND a.images IS NOT NULL\r\n          AND array_length(a.images, 1) > 0\r\n      ) THEN true\r\n      ELSE false\r\n    END,\r\n    -- Activities (ordered by order_idx)\r\n    'activities', COALESCE(\r\n      (\r\n        SELECT jsonb_agg(\r\n          jsonb_build_object(\r\n            'id', a.id,\r\n            'title', a.title,\r\n            'images', a.images,\r\n            'order_idx', a.order_idx,\r\n            'location_name', a.location_name,\r\n            'location_desc', a.location_desc,\r\n            'location_url', a.location_url,\r\n            'location_notes', a.location_notes,\r\n            'additional_info', a.additional_info,\r\n            'tags', a.tags\r\n          ) ORDER BY a.order_idx ASC\r\n        )\r\n        FROM activities a\r\n        WHERE a.post_id = p.id\r\n      ),\r\n      '[]'::jsonb\r\n    ),\r\n    -- RSVP data (only for hangouts)\r\n    'rsvp_data', CASE \r\n      WHEN p.type = 'hangout' THEN\r\n        jsonb_build_object(\r\n          'users', COALESCE(rsvp_users.json_array, '[]'::jsonb),\r\n          'currentUserStatus', COALESCE(user_rsvp.status, NULL)\r\n        )\r\n      ELSE NULL\r\n    END\r\n  )\r\n  INTO v_post\r\n  FROM posts p\r\n  -- Join author profile\r\n  INNER JOIN profiles author_profile ON author_profile.user_id = p.author_id\r\n  -- Join follow status (viewer following author)\r\n  LEFT JOIN follows mutual_follow ON \r\n    mutual_follow.follower_id = v_viewer_profile_id \r\n    AND mutual_follow.following_id = author_profile.id\r\n  -- Join reverse follow (author following viewer, for mutual check)\r\n  LEFT JOIN follows reverse_follow ON \r\n    reverse_follow.follower_id = author_profile.id \r\n    AND reverse_follow.following_id = v_viewer_profile_id\r\n  -- Join like status\r\n  LEFT JOIN post_likes user_like ON \r\n    user_like.post_id = p.id \r\n    AND user_like.user_id = p_viewer_user_id\r\n  -- Join save status\r\n  LEFT JOIN saved_posts user_save ON \r\n    user_save.post_id = p.id \r\n    AND user_save.user_id = p_viewer_user_id\r\n  -- Join RSVP users (only \"going\" status, limit 10)\r\n  LEFT JOIN LATERAL (\r\n    SELECT COALESCE(\r\n      (\r\n        SELECT jsonb_agg(\r\n          jsonb_build_object(\r\n            'id', sub.profile_id,\r\n            'username', sub.username,\r\n            'display_name', sub.display_name,\r\n            'avatar_url', sub.avatar_url,\r\n            'status', sub.status,\r\n            'created_at', sub.created_at\r\n          ) ORDER BY sub.created_at DESC\r\n        )\r\n        FROM (\r\n          SELECT \r\n            rsvp_profile.id as profile_id,\r\n            rsvp_profile.username,\r\n            rsvp_profile.display_name,\r\n            rsvp_profile.avatar_url,\r\n            rsvp_response.status,\r\n            rsvp_response.created_at\r\n          FROM rsvp_responses rsvp_response\r\n          INNER JOIN profiles rsvp_profile ON rsvp_profile.user_id = rsvp_response.user_id\r\n          WHERE rsvp_response.post_id = p.id\r\n            AND rsvp_response.status = 'going'\r\n          ORDER BY rsvp_response.created_at DESC\r\n          LIMIT 10\r\n        ) sub\r\n      ),\r\n      '[]'::jsonb\r\n    ) as json_array\r\n  ) rsvp_users ON true\r\n  -- Join user's RSVP status\r\n  LEFT JOIN rsvp_responses user_rsvp ON \r\n    user_rsvp.post_id = p.id \r\n    AND user_rsvp.user_id = p_viewer_user_id\r\n  WHERE p.id = p_post_id\r\n    -- Privacy filter: show post if:\r\n    -- 1. Author is not private, OR\r\n    -- 2. Author is private AND viewer is following (approved status), OR\r\n    -- 3. Viewer is the author\r\n    AND (\r\n      author_profile.is_private = false\r\n      OR v_viewer_profile_id = author_profile.id\r\n      OR (author_profile.is_private = true AND mutual_follow.status = 'approved')\r\n    )\r\n    -- Visibility filter: show post if:\r\n    -- 1. Visibility is 'public' or NULL, OR\r\n    -- 2. Visibility is 'friends' AND mutual follow exists, OR\r\n    -- 3. Viewer is the author\r\n    AND (\r\n      p.visibility IS NULL \r\n      OR p.visibility = 'public'\r\n      OR p.visibility = 'anonymous'\r\n      OR v_viewer_profile_id = author_profile.id\r\n      OR (p.visibility = 'friends' AND mutual_follow.status = 'approved' AND reverse_follow.status = 'approved')\r\n    );\r\n\r\n  -- Step 3: Build final result\r\n  IF v_post IS NULL THEN\r\n    v_result := jsonb_build_object('post', NULL, 'error', 'Post not found or access denied');\r\n  ELSE\r\n    v_result := jsonb_build_object('post', v_post);\r\n  END IF;\r\n\r\n  RETURN v_result;\r\nEND;\r\n$function$\n"
  },
  {
    "function_name": "get_rsvp_list_with_profiles",
    "definition": "CREATE OR REPLACE FUNCTION public.get_rsvp_list_with_profiles(p_post_id uuid, p_viewer_user_id uuid DEFAULT NULL::uuid)\n RETURNS jsonb\n LANGUAGE plpgsql\n STABLE SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_result JSONB;\r\n  v_users JSONB;\r\n  v_current_user_status TEXT;\r\nBEGIN\r\n  -- Step 1: Get all RSVP users with their profiles\r\n  SELECT COALESCE(\r\n    jsonb_agg(\r\n      jsonb_build_object(\r\n        'id', p.id,\r\n        'username', p.username,\r\n        'display_name', p.display_name,\r\n        'avatar_url', p.avatar_url,\r\n        'status', r.status,\r\n        'created_at', r.created_at\r\n      ) ORDER BY r.created_at DESC\r\n    ),\r\n    '[]'::jsonb\r\n  )\r\n  INTO v_users\r\n  FROM rsvp_responses r\r\n  INNER JOIN profiles p ON p.user_id = r.user_id\r\n  WHERE r.post_id = p_post_id;\r\n\r\n  -- Step 2: Get current user's RSVP status (if viewer_user_id is provided)\r\n  IF p_viewer_user_id IS NOT NULL THEN\r\n    SELECT r.status\r\n    INTO v_current_user_status\r\n    FROM rsvp_responses r\r\n    WHERE r.post_id = p_post_id\r\n      AND r.user_id = p_viewer_user_id\r\n    LIMIT 1;\r\n  END IF;\r\n\r\n  -- Step 3: Build final result\r\n  v_result := jsonb_build_object(\r\n    'users', COALESCE(v_users, '[]'::jsonb),\r\n    'currentUserStatus', v_current_user_status\r\n  );\r\n\r\n  RETURN v_result;\r\nEND;\r\n$function$\n"
  },
  {
    "function_name": "get_user_posts_created_with_related_data",
    "definition": "CREATE OR REPLACE FUNCTION public.get_user_posts_created_with_related_data(p_user_id uuid, p_viewer_user_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0, p_include_drafts boolean DEFAULT false, p_is_owner boolean DEFAULT false)\n RETURNS jsonb\n LANGUAGE plpgsql\n STABLE SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_viewer_profile_id UUID;\r\n  v_user_profile_id UUID;\r\n  v_result JSONB;\r\n  v_posts JSONB;\r\nBEGIN\r\n  SELECT id INTO v_user_profile_id\r\n  FROM profiles\r\n  WHERE user_id = p_user_id\r\n  LIMIT 1;\r\n\r\n  IF p_viewer_user_id IS NOT NULL THEN\r\n    SELECT id INTO v_viewer_profile_id\r\n    FROM profiles\r\n    WHERE user_id = p_viewer_user_id\r\n    LIMIT 1;\r\n  END IF;\r\n\r\n  WITH filtered_posts AS (\r\n    SELECT DISTINCT\r\n      p.id,\r\n      p.type,\r\n      p.caption,\r\n      p.is_anonymous,\r\n      p.anonymous_name,\r\n      p.anonymous_avatar,\r\n      p.created_at,\r\n      p.selected_dates,\r\n      p.tags,\r\n      p.author_id,\r\n      p.status,\r\n      jsonb_build_object(\r\n        'id', author_profile.id,\r\n        'username', author_profile.username,\r\n        'display_name', author_profile.display_name,\r\n        'avatar_url', author_profile.avatar_url,\r\n        'is_private', author_profile.is_private\r\n      ) as author,\r\n      CASE\r\n        WHEN v_viewer_profile_id IS NULL THEN 'none'\r\n        WHEN v_viewer_profile_id = author_profile.id THEN 'self'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n             AND reverse_follow.follower_id IS NOT NULL AND reverse_follow.status = 'approved' \r\n        THEN 'friends'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n        THEN 'following'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'pending' \r\n        THEN 'pending'\r\n        ELSE 'none'\r\n      END as follow_status,\r\n      CASE WHEN p_viewer_user_id IS NOT NULL AND user_like.post_id IS NOT NULL THEN true ELSE false END as is_liked,\r\n      CASE WHEN p_viewer_user_id IS NOT NULL AND user_save.post_id IS NOT NULL THEN true ELSE false END as is_saved,\r\n      (\r\n        SELECT COUNT(*)\r\n        FROM comments c\r\n        WHERE c.post_id = p.id\r\n          AND c.is_deleted = false\r\n      ) as comment_count,\r\n      CASE \r\n        WHEN EXISTS (\r\n          SELECT 1 \r\n          FROM activities a \r\n          WHERE a.post_id = p.id \r\n            AND a.images IS NOT NULL \r\n            AND array_length(a.images, 1) > 0\r\n        ) THEN true \r\n        ELSE false \r\n      END as has_images,\r\n      -- ✅ FIXED: Cast text[] to jsonb\r\n      COALESCE(\r\n        (\r\n          SELECT jsonb_agg(\r\n            jsonb_build_object(\r\n              'id', a.id,\r\n              'images', to_jsonb(a.images),\r\n              'created_at', a.created_at\r\n            ) ORDER BY a.created_at\r\n          )\r\n          FROM activities a\r\n          WHERE a.post_id = p.id\r\n        ),\r\n        '[]'::jsonb\r\n      ) as activities,\r\n      CASE \r\n        WHEN p.type = 'hangout' THEN\r\n          jsonb_build_object(\r\n            'users', COALESCE(rsvp_users.json_array, '[]'::jsonb),\r\n            'currentUserStatus', COALESCE(user_rsvp.status, NULL)\r\n          )\r\n        ELSE NULL\r\n      END as rsvp_data\r\n    FROM posts p\r\n    INNER JOIN profiles author_profile ON author_profile.user_id = p.author_id\r\n    LEFT JOIN follows mutual_follow ON \r\n      mutual_follow.follower_id = v_viewer_profile_id \r\n      AND mutual_follow.following_id = author_profile.id\r\n    LEFT JOIN follows reverse_follow ON \r\n      reverse_follow.follower_id = author_profile.id \r\n      AND reverse_follow.following_id = v_viewer_profile_id\r\n    LEFT JOIN post_likes user_like ON \r\n      user_like.post_id = p.id \r\n      AND user_like.user_id = p_viewer_user_id\r\n    LEFT JOIN saved_posts user_save ON \r\n      user_save.post_id = p.id \r\n      AND user_save.user_id = p_viewer_user_id\r\n    LEFT JOIN LATERAL (\r\n      SELECT COALESCE(\r\n        (\r\n          SELECT jsonb_agg(\r\n          jsonb_build_object(\r\n            'id', sub.profile_id,\r\n            'username', sub.username,\r\n            'display_name', sub.display_name,\r\n            'avatar_url', sub.avatar_url,\r\n            'status', sub.status,\r\n            'created_at', sub.created_at\r\n          ) ORDER BY sub.created_at DESC\r\n          )\r\n          FROM (\r\n            SELECT \r\n              rsvp_profile.id as profile_id,\r\n              rsvp_profile.username,\r\n              rsvp_profile.display_name,\r\n              rsvp_profile.avatar_url,\r\n              rsvp_response.status,\r\n              rsvp_response.created_at\r\n            FROM rsvp_responses rsvp_response\r\n            INNER JOIN profiles rsvp_profile ON rsvp_profile.user_id = rsvp_response.user_id\r\n            WHERE rsvp_response.post_id = p.id\r\n              AND rsvp_response.status = 'going'\r\n            ORDER BY rsvp_response.created_at DESC\r\n            LIMIT 10\r\n          ) sub\r\n        ),\r\n        '[]'::jsonb\r\n      ) as json_array\r\n    ) rsvp_users ON true\r\n    LEFT JOIN rsvp_responses user_rsvp ON \r\n      user_rsvp.post_id = p.id \r\n      AND user_rsvp.user_id = p_viewer_user_id\r\n    WHERE\r\n      p.author_id = p_user_id\r\n      AND (p_is_owner = true OR p.is_anonymous IS NULL OR p.is_anonymous = false)\r\n      AND (\r\n        (p_is_owner = false AND p.status = 'published')\r\n        OR (p_is_owner = true AND p_include_drafts = true)\r\n        OR (p_is_owner = true AND p_include_drafts = false AND p.status = 'published')\r\n      )\r\n      AND (\r\n        author_profile.is_private = false\r\n        OR v_viewer_profile_id = author_profile.id\r\n        OR (author_profile.is_private = true AND mutual_follow.status = 'approved')\r\n      )\r\n    ORDER BY p.created_at DESC\r\n    LIMIT p_limit\r\n    OFFSET p_offset\r\n  )\r\n  SELECT jsonb_agg(\r\n    jsonb_build_object(\r\n      'id', id,\r\n      'type', type,\r\n      'caption', caption,\r\n      'is_anonymous', is_anonymous,\r\n      'anonymous_name', anonymous_name,\r\n      'anonymous_avatar', anonymous_avatar,\r\n      'created_at', created_at,\r\n      'selected_dates', selected_dates,\r\n      'tags', tags,\r\n      'author_id', author_id,\r\n      'status', status,\r\n      'author', author,\r\n      'follow_status', follow_status,\r\n      'is_liked', is_liked,\r\n      'is_saved', is_saved,\r\n      'comment_count', comment_count,\r\n      'has_images', has_images,\r\n      'activities', activities,\r\n      'rsvp_data', rsvp_data\r\n    ) ORDER BY created_at DESC\r\n  )\r\n  INTO v_posts\r\n  FROM filtered_posts;\r\n\r\n  v_result := jsonb_build_object(\r\n    'posts', COALESCE(v_posts, '[]'::jsonb),\r\n    'count', jsonb_array_length(COALESCE(v_posts, '[]'::jsonb))\r\n  );\r\n\r\n  RETURN v_result;\r\nEND;\r\n$function$\n"
  },
  {
    "function_name": "get_user_posts_liked_with_related_data",
    "definition": "CREATE OR REPLACE FUNCTION public.get_user_posts_liked_with_related_data(p_user_id uuid, p_viewer_user_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0)\n RETURNS jsonb\n LANGUAGE plpgsql\n STABLE SECURITY DEFINER\nAS $function$\r\nDECLARE\r\n  v_viewer_profile_id UUID;\r\n  v_result JSONB;\r\n  v_posts JSONB;\r\nBEGIN\r\n  IF p_viewer_user_id IS NOT NULL THEN\r\n    SELECT id INTO v_viewer_profile_id\r\n    FROM profiles\r\n    WHERE user_id = p_viewer_user_id\r\n    LIMIT 1;\r\n  END IF;\r\n\r\n  WITH filtered_posts AS (\r\n    SELECT DISTINCT\r\n      p.id,\r\n      p.type,\r\n      p.caption,\r\n      p.is_anonymous,\r\n      p.anonymous_name,\r\n      p.anonymous_avatar,\r\n      p.created_at,\r\n      p.selected_dates,\r\n      p.tags,\r\n      p.author_id,\r\n      pl.id as like_id,\r\n      pl.created_at as liked_at,\r\n      jsonb_build_object(\r\n        'id', author_profile.id,\r\n        'username', author_profile.username,\r\n        'display_name', author_profile.display_name,\r\n        'avatar_url', author_profile.avatar_url,\r\n        'is_private', author_profile.is_private\r\n      ) as author,\r\n      CASE\r\n        WHEN v_viewer_profile_id IS NULL THEN 'none'\r\n        WHEN v_viewer_profile_id = author_profile.id THEN 'self'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n             AND reverse_follow.follower_id IS NOT NULL AND reverse_follow.status = 'approved' \r\n        THEN 'friends'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'approved' \r\n        THEN 'following'\r\n        WHEN mutual_follow.follower_id IS NOT NULL AND mutual_follow.status = 'pending' \r\n        THEN 'pending'\r\n        ELSE 'none'\r\n      END as follow_status,\r\n      CASE WHEN p_viewer_user_id IS NOT NULL AND user_like.post_id IS NOT NULL THEN true ELSE false END as is_liked,\r\n      CASE WHEN p_viewer_user_id IS NOT NULL AND user_save.post_id IS NOT NULL THEN true ELSE false END as is_saved,\r\n      (\r\n        SELECT COUNT(*)\r\n        FROM comments c\r\n        WHERE c.post_id = p.id\r\n          AND c.is_deleted = false\r\n      ) as comment_count,\r\n      CASE \r\n        WHEN EXISTS (\r\n          SELECT 1 \r\n          FROM activities a \r\n          WHERE a.post_id = p.id \r\n            AND a.images IS NOT NULL \r\n            AND array_length(a.images, 1) > 0\r\n        ) THEN true \r\n        ELSE false \r\n      END as has_images,\r\n      COALESCE(\r\n        (\r\n          SELECT jsonb_agg(\r\n            jsonb_build_object(\r\n              'id', a.id,\r\n              'images', to_jsonb(a.images),\r\n              'created_at', a.created_at\r\n            ) ORDER BY a.created_at\r\n          )\r\n          FROM activities a\r\n          WHERE a.post_id = p.id\r\n        ),\r\n        '[]'::jsonb\r\n      ) as activities,\r\n      CASE \r\n        WHEN p.type = 'hangout' THEN\r\n          jsonb_build_object(\r\n            'users', COALESCE(rsvp_users.json_array, '[]'::jsonb),\r\n            'currentUserStatus', COALESCE(user_rsvp.status, NULL)\r\n          )\r\n        ELSE NULL\r\n      END as rsvp_data\r\n    FROM post_likes pl\r\n    INNER JOIN posts p ON p.id = pl.post_id\r\n    INNER JOIN profiles author_profile ON author_profile.user_id = p.author_id\r\n    LEFT JOIN follows mutual_follow ON \r\n      mutual_follow.follower_id = v_viewer_profile_id \r\n      AND mutual_follow.following_id = author_profile.id\r\n    LEFT JOIN follows reverse_follow ON \r\n      reverse_follow.follower_id = author_profile.id \r\n      AND reverse_follow.following_id = v_viewer_profile_id\r\n    LEFT JOIN post_likes user_like ON \r\n      user_like.post_id = p.id \r\n      AND user_like.user_id = p_viewer_user_id\r\n    LEFT JOIN saved_posts user_save ON \r\n      user_save.post_id = p.id \r\n      AND user_save.user_id = p_viewer_user_id\r\n    LEFT JOIN LATERAL (\r\n      SELECT COALESCE(\r\n        (\r\n          SELECT jsonb_agg(\r\n            jsonb_build_object(\r\n              'id', sub.profile_id,\r\n              'username', sub.username,\r\n              'display_name', sub.display_name,\r\n              'avatar_url', sub.avatar_url,\r\n              'status', sub.status,\r\n              'created_at', sub.created_at\r\n            ) ORDER BY sub.created_at DESC\r\n          )\r\n          FROM (\r\n            SELECT \r\n              rsvp_profile.id as profile_id,\r\n              rsvp_profile.username,\r\n              rsvp_profile.display_name,\r\n              rsvp_profile.avatar_url,\r\n              rsvp_response.status,\r\n              rsvp_response.created_at\r\n            FROM rsvp_responses rsvp_response\r\n            INNER JOIN profiles rsvp_profile ON rsvp_profile.user_id = rsvp_response.user_id\r\n            WHERE rsvp_response.post_id = p.id\r\n              AND rsvp_response.status = 'going'\r\n            ORDER BY rsvp_response.created_at DESC\r\n            LIMIT 10\r\n          ) sub\r\n        ),\r\n        '[]'::jsonb\r\n      ) as json_array\r\n    ) rsvp_users ON true\r\n    LEFT JOIN rsvp_responses user_rsvp ON \r\n      user_rsvp.post_id = p.id \r\n      AND user_rsvp.user_id = p_viewer_user_id\r\n    WHERE\r\n      pl.user_id = p_user_id\r\n      AND p.status = 'published'\r\n      AND (\r\n        author_profile.is_private = false\r\n        OR v_viewer_profile_id = author_profile.id\r\n        OR (author_profile.is_private = true AND mutual_follow.status = 'approved')\r\n      )\r\n    ORDER BY pl.created_at DESC\r\n    LIMIT p_limit\r\n    OFFSET p_offset\r\n  )\r\n  SELECT jsonb_agg(\r\n    jsonb_build_object(\r\n      'id', id,\r\n      'type', type,\r\n      'caption', caption,\r\n      'is_anonymous', is_anonymous,\r\n      'anonymous_name', anonymous_name,\r\n      'anonymous_avatar', anonymous_avatar,\r\n      'created_at', created_at,\r\n      'selected_dates', selected_dates,\r\n      'tags', tags,\r\n      'author_id', author_id,\r\n      'like_id', like_id,\r\n      'liked_at', liked_at,\r\n      'author', author,\r\n      'follow_status', follow_status,\r\n      'is_liked', is_liked,\r\n      'is_saved', is_saved,\r\n      'comment_count', comment_count,\r\n      'has_images', has_images,\r\n      'activities', activities,\r\n      'rsvp_data', rsvp_data\r\n    ) ORDER BY liked_at DESC\r\n  )\r\n  INTO v_posts\r\n  FROM filtered_posts;\r\n\r\n  v_result := jsonb_build_object(\r\n    'posts', COALESCE(v_posts, '[]'::jsonb),\r\n    'count', jsonb_array_length(COALESCE(v_posts, '[]'::jsonb))\r\n  );\r\n\r\n  RETURN v_result;\r\nEND;\r\n$function$\n"
